const fs = require('fs');
const path = require('path');

const componentsDir = path.join(__dirname, '..', 'public', 'components');
const outFile = path.join(__dirname, '..', 'public', 'js', 'layout-components.v5.js');

const files = fs.readdirSync(componentsDir).filter((name) => name.endsWith('.html'));

const entries = files.map((name) => {
    const content = fs.readFileSync(path.join(componentsDir, name), 'utf8');
    const key = `components/${name}`;
    const escaped = JSON.stringify(content);
    return `    ${JSON.stringify(key)}: ${escaped}`;
});

const output = `// Auto-generated by scripts/bundle-components.js — do not edit by hand.
// Re-run: node scripts/bundle-components.js

export const LAYOUT_COMPONENTS = {
${entries.join(',\n')}
};

export function getEmbeddedComponent(path) {
    const clean = String(path || '').trim().replace(/^\\//, '');
    return LAYOUT_COMPONENTS[clean] || LAYOUT_COMPONENTS[\`components/\${clean.split('/').pop()}\`] || null;
}
`;

fs.writeFileSync(outFile, output, 'utf8');
console.log(`Bundled ${files.length} components -> ${outFile}`);